refsection.programlisting:
CREATE TABLE raster_proportions_rast ( name text, rast raster );
INSERT INTO raster_proportions_rast (name, rast) VALUES ( '2x2 raster covering 0,0 to 10,10', ST_MakeEmptyRaster( 2, 2, -- raster width/height in pixels 0, 10, -- upper-left corner x/y coordinates 5, -5, -- pixel width/height in ground units 0, 0, -- skew x/y 0 -- SRID ));
-- -- This rotated square polygon covers half of each cell in the -- raster. -- SELECT name, ST_DumpValues( ST_IntersectionFractions( rast, 'POLYGON((5 0, 0 5, 5 10, 10 5, 5 0))'::geometry),1) FROM raster_proportions_rast;
2x2 raster covering 0,0 to 10,10 --------------------------------- {{0.5,0.5},{0.5,0.5}}
